import * as React from "react";
import { Helmet } from "react-helmet";
import PropTypes from "prop-types";
import _ from "lodash";
import url from "url";

import ImageMeta from "./ImageMeta";
import config from "../../utils/siteConfig";

// 讀取 JSON 數據
import settingsData from "../../data/blog.json";

/**
 * WebsiteMeta component
 *
 * Loads global website meta settings from a local JSON file instead of Ghost API.
 */
const WebsiteMeta = ({ data, canonical, title, description, image, type }) => {
    const settings = settingsData.allGhostSettings.edges[0].node;

    const publisherLogo = url.resolve(
        config.siteUrl,
        settings.logo || config.siteIcon
    );
    let shareImage =
        image || data.feature_image || _.get(settings, `cover_image`, null);

    shareImage = shareImage ? url.resolve(config.siteUrl, shareImage) : null;

    description =
        description ||
        data.meta_description ||
        data.description ||
        config.siteDescriptionMeta ||
        settings.description;
    title = `${title || data.meta_title || data.name || data.title} - ${
        settings.title
    }`;

    const jsonLd = {
        "@context": `https://schema.org/`,
        "@type": type,
        url: canonical,
        image: shareImage
            ? {
                  "@type": `ImageObject`,
                  url: shareImage,
                  width: config.shareImageWidth,
                  height: config.shareImageHeight,
              }
            : undefined,
        publisher: {
            "@type": `Organization`,
            name: settings.title,
            logo: {
                "@type": `ImageObject`,
                url: publisherLogo,
                width: 60,
                height: 60,
            },
        },
        mainEntityOfPage: {
            "@type": `WebPage`,
            "@id": config.siteUrl,
        },
        description,
    };

    return (
        <>
            <Helmet>
                <title>{title}</title>
                <meta name="description" content={description} />
                <link rel="canonical" href={canonical} />
                <meta property="og:site_name" content={settings.title} />
                <meta property="og:type" content="website" />
                <meta property="og:title" content={title} />
                <meta property="og:description" content={description} />
                <meta property="og:url" content={canonical} />
                <meta name="github:title" content={title} />
                <meta name="github:description" content={description} />
                <meta name="github:url" content={canonical} />
                {settings.github && (
                    <meta
                        name="github:site"
                        content={`https://github.com/${settings.github.replace(
                            /^@/,
                            ``
                        )}/`}
                    />
                )}
                {settings.github && (
                    <meta name="github:creator" content={settings.github} />
                )}
                <script type="application/ld+json">
                    {JSON.stringify(jsonLd, undefined, 4)}
                </script>
            </Helmet>
            <ImageMeta image={shareImage} />
        </>
    );
};

WebsiteMeta.propTypes = {
    data: PropTypes.shape({
        title: PropTypes.string,
        meta_title: PropTypes.string,
        meta_description: PropTypes.string,
        name: PropTypes.string,
        feature_image: PropTypes.string,
        description: PropTypes.string,
        bio: PropTypes.string,
        profile_image: PropTypes.string,
    }).isRequired,
    canonical: PropTypes.string.isRequired,
    title: PropTypes.string,
    description: PropTypes.string,
    image: PropTypes.string,
    type: PropTypes.oneOf([`WebSite`, `Series`]).isRequired,
};

export default WebsiteMeta;
