import * as React from "react";
import { Helmet } from "react-helmet";
import PropTypes from "prop-types";
import _ from "lodash";
import url from "url";

import getAuthorProperties from "./getAuthorProperties";
import ImageMeta from "./ImageMeta";
import config from "../../utils/siteConfig";

// 讀取 JSON 數據
import settingsData from "../../data/blog.json";

import { tags as tagsHelper } from "@tryghost/helpers";

/**
 * ArticleMetaGhost component
 *
 * Loads meta settings from a local JSON file instead of Ghost API.
 */
const ArticleMetaGhost = ({ canonical }) => {
    const settings = settingsData.allGhostSettings.edges[0].node;
    const data = settingsData;

    const author = getAuthorProperties(data.tech_type);
    const publicTags = _.map(
        tagsHelper(data, { visibility: `public`, fn: (tag) => tag }),
        `name`
    );
    const primaryTag = publicTags[0] || ``;
    const shareImage = data.feature_image
        ? data.feature_image
        : _.get(settings, `cover_image`, null);
    const publisherLogo =
        settings.logo || config.siteIcon
            ? url.resolve(config.siteUrl, settings.logo || config.siteIcon)
            : null;

    const jsonLd = {
        "@context": `https://schema.org/`,
        "@type": `Article`,
        author: {
            "@type": `Person`,
            name: author.name,
            image: author.image ? author.image : undefined,
            sameAs: author.sameAsArray ? author.sameAsArray : undefined,
        },
        keywords: publicTags.length ? publicTags.join(`, `) : undefined,
        headline: data.meta_title || data.title,
        url: canonical,
        datePublished: data.published_at,
        dateModified: data.updated_at,
        image: shareImage
            ? {
                  "@type": `ImageObject`,
                  url: shareImage,
                  width: config.shareImageWidth,
                  height: config.shareImageHeight,
              }
            : undefined,
        publisher: {
            "@type": `Organization`,
            name: settings.title,
            logo: {
                "@type": `ImageObject`,
                url: publisherLogo,
                width: 60,
                height: 60,
            },
        },
        description: data.meta_description || data.excerpt,
        mainEntityOfPage: {
            "@type": `WebPage`,
            "@id": config.siteUrl,
        },
    };

    return (
        <>
            <Helmet>
                <title>{data.meta_title || data.title}</title>
                <meta
                    name="description"
                    content={data.meta_description || data.excerpt}
                />
                <link rel="canonical" href={canonical} />

                <meta property="og:site_name" content={settings.title} />
                <meta property="og:type" content="article" />
                <meta
                    property="og:title"
                    content={
                        data.og_title ||
                        data.meta_title ||
                        data.title
                    }
                />
                <meta
                    property="og:description"
                    content={
                        data.og_description ||
                        data.excerpt ||
                        data.meta_description
                    }
                />
                <meta property="og:url" content={canonical} />
                <meta
                    property="article:published_time"
                    content={data.published_at}
                />
                <meta
                    property="article:modified_time"
                    content={data.updated_at}
                />
                {publicTags.map((keyword, i) => (
                    <meta property="article:tag" content={keyword} key={i} />
                ))}
                {author.linkedinUrl && (
                    <meta
                        property="article:author"
                        content={author.linkedinUrl}
                    />
                )}

                <meta
                    name="github:title"
                    content={
                        data.github_title ||
                        data.meta_title ||
                        data.title
                    }
                />
                <meta
                    name="github:description"
                    content={
                        data.github_description ||
                        data.excerpt ||
                        data.meta_description
                    }
                />
                <meta name="github:url" content={canonical} />
                <meta name="github:label1" content="Written by" />
                <meta name="github:data1" content={author.name} />
                {primaryTag && (
                    <meta name="github:label2" content="Filed under" />
                )}
                {primaryTag && (
                    <meta name="github:data2" content={primaryTag} />
                )}

                {settings.github && (
                    <meta
                        name="github:site"
                        content={`https://github.com/${settings.github.replace(
                            /^@/,
                            ``
                        )}/`}
                    />
                )}
                {settings.github && (
                    <meta name="github:creator" content={settings.github} />
                )}
                <script type="application/ld+json">
                    {JSON.stringify(jsonLd, undefined, 4)}
                </script>
            </Helmet>
            <ImageMeta image={shareImage} />
        </>
    );
};

ArticleMetaGhost.propTypes = {
    data: PropTypes.shape({
        title: PropTypes.string.isRequired,
        published_at: PropTypes.string.isRequired,
        updated_at: PropTypes.string.isRequired,
        meta_title: PropTypes.string,
        meta_description: PropTypes.string,
        tech_type: PropTypes.object.isRequired,
        feature_image: PropTypes.string,
        tags: PropTypes.arrayOf(
            PropTypes.shape({
                name: PropTypes.string,
                slug: PropTypes.string,
                visibility: PropTypes.string,
            })
        ),
        primaryTag: PropTypes.shape({
            name: PropTypes.string,
        }),
        og_title: PropTypes.string,
        og_description: PropTypes.string,
        github_title: PropTypes.string,
        github_description: PropTypes.string,
        excerpt: PropTypes.string.isRequired,
    }).isRequired,
    canonical: PropTypes.string.isRequired,
};

export default ArticleMetaGhost;
