import * as React from "react";
import PropTypes from "prop-types";
import url from "url";

import config from "../../utils/siteConfig";
import ArticleMeta from "./ArticleMeta";
import WebsiteMeta from "./WebsiteMeta";
import AuthorMeta from "./AuthorMeta";

// 讀取 JSON 數據
import settingsData from "../../data/blog.json";

/**
 * MetaData will generate all relevant meta data information incl.
 * JSON-LD (schema.org), Open Graph (linkedin) and github properties.
 */
const MetaData = ({ data, title, description, image, location }) => {
    const canonical = url.resolve(config.siteUrl, location.pathname);
    const settings = settingsData.allGhostSettings.edges[0].node;
    const { ghostPost, ghostPortfolio, ghostAuthor, ghostPage } = data;

    if (ghostPost) {
        return <ArticleMeta data={ghostPost} canonical={canonical} />;
    } else if (ghostPortfolio) {
        return <WebsiteMeta data={ghostPortfolio} canonical={canonical} type="Series" />;
    } else if (ghostAuthor) {
        return <AuthorMeta data={ghostAuthor} canonical={canonical} />;
    } else if (ghostPage) {
        return <WebsiteMeta data={ghostPage} canonical={canonical} type="WebSite" />;
    } else {
        title = title || config.siteTitleMeta || settings.title;
        description = description || config.siteDescriptionMeta || settings.description;
        image = image || settings.cover_image || null;

        image = image ? url.resolve(config.siteUrl, image) : null;

        return (
            <WebsiteMeta
                data={{}}
                canonical={canonical}
                title={title}
                description={description}
                image={image}
                type="WebSite"
            />
        );
    }
};

MetaData.defaultProps = {
    data: {},
};

MetaData.propTypes = {
    data: PropTypes.shape({
        ghostPost: PropTypes.object,
        ghostPortfolio: PropTypes.object,
        ghostAuthor: PropTypes.object,
        ghostPage: PropTypes.object,
    }).isRequired,
    location: PropTypes.shape({
        pathname: PropTypes.string.isRequired,
    }).isRequired,
    title: PropTypes.string,
    description: PropTypes.string,
    image: PropTypes.string,
};

export default MetaData;
